    let cy: number = this.rand.nextInt(/* D_CAST(int) */ (Field.NEXT_BLOCK_AREA_SIZE * 0.6)) + /* D_CAST(int) */ (Field.NEXT_BLOCK_AREA_SIZE * 0.2);
    cy += this.nextBlockY;
    let w: number = this.rand.nextInt(/* D_CAST(int) */ (Field.BLOCK_SIZE_X * 0.33)) + /* D_CAST(int) */ (Field.BLOCK_SIZE_X * 0.33);
    let h: number = this.rand.nextInt(/* D_CAST(int) */ (Field.NEXT_BLOCK_AREA_SIZE * 0.24)) + /* D_CAST(int) */ (Field.NEXT_BLOCK_AREA_SIZE * 0.33);
    cx -= w / 2;
    cy -= h / 2;
