        Screen.setColor(this.baseColor[p.ci][0] * p.or * 0.66,
                        this.baseColor[p.ci][1] * p.og * 0.66,
                        this.baseColor[p.ci][2] * p.ob * 0.66);
        glVertex3(sx + p.x, sy - p.y, p.z);
        glVertex3(sx + p.x + Field.PANEL_WIDTH, sy - p.y, p.z);
        glVertex3(sx + p.x + Field.PANEL_WIDTH, sy - p.y - Field.PANEL_WIDTH, p.z);
        glVertex3(sx + p.x, sy - p.y - Field.PANEL_WIDTH, p.z);
        Screen.setColor(this.baseColor[p.ci][0] * 0.33,
                        this.baseColor[p.ci][1] * 0.33,
                        this.baseColor[p.ci][2] * 0.33);
        glVertex2(sx, sy);
        glVertex2(sx + this.BLOCK_WIDTH, sy);
        glVertex2(sx + this.BLOCK_WIDTH, sy - this.BLOCK_WIDTH);
        glVertex2(sx, sy - this.BLOCK_WIDTH);
        sx += this.BLOCK_WIDTH;
