  private static degBlockOfs: number[][] = [[0, -1], [1, 0], [0, 1], [-1, 0]];

  private calcPlatformDeg(x: number, y: number): number {
    let d: number = this.rand.nextInt(4);
    for (let i = 0; i < 4; i++) {
      if (!this.checkBlock(x + Field.degBlockOfs[d][0], y + Field.degBlockOfs[d][1], -1, true)) {
        let pd: number = d * PI / 2;
        let ox: number = x + Field.degBlockOfs[d][0];
        let oy: number = y + Field.degBlockOfs[d][1];
        let td: number = d;
        td--;
        if (td < 0)
          td = 3;
        let b1: boolean = this.checkBlock(ox +  Field.degBlockOfs[td][0], oy +  Field.degBlockOfs[td][1], -1, true);
        td = d;
        td++;
        if (td >= 4)
          td = 0;
        let b2: boolean = this.checkBlock(ox +  Field.degBlockOfs[td][0], oy +  Field.degBlockOfs[td][1], -1, true);
        if (!b1 && b2)
          pd -= PI / 4;
        if (b1 && !b2)
          pd += PI / 4;
        Math.normalizeDeg(pd);
        return pd;
      }
      d++;
      if (d >= 4)
        d = 0;
    }
    return -99999;
  }

  public countAroundBlock(x: number, y: number, th: number = 0): number {
    let c: number = 0;
    if (this.checkBlock(x, y - 1, th))
      c++;
    if (this.checkBlock(x + 1, y, th))
      c++;
    if (this.checkBlock(x, y + 1, th))
      c++;
    if (this.checkBlock(x - 1, y, th))
      c++;
    return c;
  }

  private checkBlock(x: number, y: number, th: number = 0, outScreen: boolean = false): boolean {
    if (x < 0 || x >= Field.BLOCK_SIZE_X)
      return outScreen;
    let by: number = y;
    if (by < 0)
      by += Field.BLOCK_SIZE_Y;
    if (by >= Field.BLOCK_SIZE_Y)
      by -= Field.BLOCK_SIZE_Y;
    return (this.block[x][by] >= th);
  }

  public checkInField(arg0: Vector | number, y?: number): boolean {
    if (arg0 instanceof Vector) {
      return this._size.contains(arg0);
    }
    if (y == null) {
      return false;
    }
    return this._size.contains(arg0, y);
  }

  public checkInOuterField(arg0: Vector | number, y?: number): boolean {
    if (arg0 instanceof Vector) {
      return this._outerSize.contains(arg0);
    }
    if (y == null) {
      return false;
    }
    return this._outerSize.contains(arg0, y);
  }

  public checkInOuterHeightField(p: Vector): boolean {
    if (p.x >= -this._size.x && p.x <= this._size.x && p.y >= -this._outerSize.y && p.y <= this._outerSize.y)
      return true;
    else
      return false;
  }

  public checkInFieldExceptTop(p: Vector): boolean {
    if (p.x >= -this._size.x && p.x <= this._size.x && p.y >= -this._size.y)
      return true;
    else
      return false;
  }

  public checkInOuterFieldExceptTop(p: Vector): boolean {
    if (p.x >= -this._outerSize.x && p.x <= this._outerSize.x &&
        p.y >= -this._outerSize.y && p.y <= this._outerSize.y * 2)
      return true;
    else
      return false;
  }

